const menu=document.querySelector('[data-menu]'),open=document.querySelector('[data-menu-open]'),close=document.querySelector('[data-menu-close]'),result=document.querySelector('[data-result]');let previous;function hide(){menu.close();open.setAttribute('aria-expanded','false');previous?.focus()}open?.addEventListener('click',()=>{previous=document.activeElement;menu.showModal();open.setAttribute('aria-expanded','true');close.focus()});close?.addEventListener('click',hide);menu?.addEventListener('cancel',event=>{event.preventDefault();hide()});menu?.addEventListener('click',event=>{if(event.target===menu)hide()});document.querySelectorAll('dialog a').forEach(link=>link.addEventListener('click',hide));document.querySelector('[data-search]')?.addEventListener('submit',event=>{event.preventDefault();const term=event.currentTarget.querySelector('input').value.trim();result.textContent=term?`Prototypresultat f\u00f6r "${term}". S\u00f6kfrasen \u00e4r bevarad inf\u00f6r en separat resursyta.`:'';result.tabIndex=-1;result.focus()});
